    "plt.suptitle('Análisis de Espectros UV-Vis de Nanopartículas', fontsize=16, y=0.98, fontweight='bold')\n",
    "plt.tight_layout()\n",
    "plt.savefig('spectroscopy_analysis_complete.png', dpi=300, bbox_inches='tight')\n",
